mapper.select:

SELECT
    a.id, a.title, a.summary, a.cover_image, a.author_id, a.author_name, a.author_avatar,
    a.publish_at, a.update_at, a.view_count, a.like_count, a.comment_count,
    a.type, a.quote_content, a.create_time, a.update_time
FROM article a




    INNER JOIN (
        SELECT article_id
        FROM article_category
        WHERE category_id IN


        #{id}


        GROUP BY article_id
        HAVING COUNT(DISTINCT category_id) = #{categoryIdSize}
    ) ac_filter ON a.id = ac_filter.article_id





    INNER JOIN (
        SELECT article_id
        FROM article_tag
        WHERE tag_id IN


        #{id}


        GROUP BY article_id
        HAVING COUNT(DISTINCT tag_id) = #{tagIdSize}
    ) tag_filter ON a.id = tag_filter.article_id





        a.type = #{type}


        AND a.author_name LIKE CONCAT('%', #{authorName}, '%')


        AND a.title LIKE CONCAT('%', #{title}, '%')


        AND DATE(a.publish_at) >= #{begin}


        AND DATE(a.publish_at) <= #{end}



ORDER BY a.publish_at DESC
